+/// All other pages start at offset 0.
+#[must_use]
+pub const fn header_offset_for_page(page_no: PageNumber) -> usize {
+    if page_no.get() == 1 {
+        DB_HEADER_SIZE as usize
+    } else {
+        0
+    }
+}
